define(function() {
    'use strict';
    
    // Save and hide AMD so marked exports to global instead of registering as AMD module
    var origDefine = typeof define !== 'undefined' ? define : undefined;
    try {
        // Temporarily delete define from global scope
        // @ts-ignore
        delete window.define;
        
        // Eval marked source in global scope — it will set window.marked
        var markedSrc = atob('');
        Function(markedSrc)();
        
        if (!window.marked) {
            throw new Error('marked failed to set window.marked');
        }
        
        window.marked.setOptions({
            gfm: true,
            breaks: false,
            headerIds: false,
            mangle: false
        });
        
        return window.marked;
    } finally {
        // Restore define for other modules
        if (origDefine) {
            window.define = origDefine;
        }
    }
});
